bomData.valueScript:
// Filter function to get all the hardware elements for the handle
let HardwareElements = GlobalFunc.find_HardwareLibraryMapping(part.pa_HardwareId);

// Cycle to add all hardware elements to the BOM
HardwareElements.forEach(info => {
  let elem = this.addbomout_Hardware();
  let HandleBOMInfo = GlobalFunc.find_HardwareLibrary(info.SupplierArticleNumber!,info.Supplier!);
  let HandleBOMName = GlobalFunc.find_PartSettings("part_Handle");

  elem.bom_Supplier=info.Supplier;
  elem.bom_SupplierArticle=info.SupplierArticleNumber;
  elem.bom_Description1=HandleBOMInfo.Description;
  elem.bom_Description2=HandleBOMInfo.Description2;
  elem.bom_Length=HandleBOMInfo.Length;
  elem.bom_Width=HandleBOMInfo.Width;
  elem.bom_Thk=HandleBOMInfo.Thickness;
  elem.bom_Color=HandleBOMInfo.Color;
  elem.bom_Weight=HandleBOMInfo.Weight;
  elem.bom_Name=HandleBOMName.BomPartDescription;
  elem.bom_Type=part._partId;
  elem.bom_PartId=part._id;
  elem.bom_ParentId=parentId;
  elem.bom_Qty=info.BomQty;
})
